			JDTORecordSet jsApplyYNChk = commDao.select(jrTobe, "com.inisteel.cim.yd.pslabyd.session.PSlabYdComm.getSlabApplyYnDualSql", logId, methodNm, "열정보 Read"); 
			String sDyd201Yn26 = "";
