							JDTORecord recL2Para = JDTORecordFactory.getInstance().create();
							recL2Para.setField("MSG_ID"				, "YDY3L001");
							recL2Para.setField("YD_INFO_SYNC_CD"	, "4");				//1:동,2:SPAN,3:열,4:BED
							recL2Para.setField("YD_STK_COL_GP"  	, slabUtils.trim(jrRow.getFieldString("YD_STK_COL_GP")));
							recL2Para.setField("YD_STK_BED_NO"  	, slabUtils.trim(jrRow.getFieldString("YD_STK_BED_NO")));
							recL2Para.setField("YD_EQP_WRK_STAT_GUBUN" , "R");// R:예약생성 D:예약/스케줄 삭제
							
							jrYdMsg = slabUtils.addSndData(jrYdMsg, commDao.getMsgL2("YDY3L001", recL2Para));
