	/**
	 *      [A] 오퍼레이션명 : 크레인작업관리 순위변경
	 *
	 * 		@ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 *      @param GridData gdReq
	 *      @return JDTORecord
	 *      @throws DAOException
	*/
	public JDTORecord trtCrnWrkMgtPM(GridData gdReq) throws DAOException {
		String methodNm = "크레인작업관리 순위변경[PSlabYdJspSeEJB.trtCrnWrkMgtPM] < " + gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();

		try {
			slabUtils.printLog(logId, methodNm, "S+", gdReq);

			String ydWbookId  = ""; //야드작업예약ID
			String ydSchPrior = ""; //야드스케쥴우선순위
			String sModifier   = slabUtils.trim(gdReq.getParam("YD_USER_ID")); //사용자
			//DAO Parameter - Log ID, Method, 수정자 Set
			JDTORecord jrParam = slabUtils.getParam(logId, methodNm, sModifier);
			JDTORecord jrRtn   = slabUtils.getParam(logId, methodNm, sModifier);
			
			//처리완료한 야드작업예약ID
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			String[] arrYdWbookId = new String[rowCnt];
			
			for (int ii = 0; ii < rowCnt; ii++) {
				/**********************************************************
				* 1. 작업예약ID Check
				**********************************************************/
			    ydWbookId  = slabUtils.trim(gdReq.getHeader("YD_WBOOK_ID" ).getValue(ii)); //야드작업예약ID
			    ydSchPrior = slabUtils.trim(gdReq.getHeader("YD_SCH_PRIOR").getValue(ii)); //야드스케쥴우선순위

			    //작업할  야드작업예약ID가 작업 완료한 야드작업예약ID에 있으면 이전에 모두 처리되었으므로 Skip
				if (slabUtils.chkExist(arrYdWbookId, ydWbookId)) { continue; }
				arrYdWbookId[ii] = ydWbookId;

				slabUtils.printLog(logId, "우선순위변경 [ " + ydWbookId + " >> " + ydSchPrior + " ]", "SL");

				/**********************************************************
				* 2. 작업예약 및 크레인스케줄 Table에  우선순위를 Update
				**********************************************************/
				jrParam.setField("YD_WBOOK_ID" , ydWbookId );
				jrParam.setField("YD_SCH_PRIOR", ydSchPrior);
				
				//작업예약 Table 우선순위 Update
				//commDao.updSlabYd("WbPrior", jrParam);
				/*
				 * UPDATE TB_YD_WRKBOOK
					   SET MODIFIER     = :V_MODIFIER
					      ,MOD_DDTT     = SYSDATE
					      ,YD_SCH_PRIOR = NVL(TO_NUMBER(:V_YD_SCH_PRIOR),1)
					 WHERE YD_WBOOK_ID  = :V_YD_WBOOK_ID
					   AND DEL_YN       = 'N'
				 */
				commDao.update(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.updSlabYdWbPrior", logId, methodNm, "작업예약(TB_YD_WRKBOOK) 야드스케쥴우선순위 수정");
				
				//크레인스케줄 Table 크레인ID, 우선순위 Update
				//jspDao.updCrnWrkMgt("CMCrnSch", jrParam);
				/*
				 *크레인작업관리 크레인변경 크레인스케줄 수정 
					UPDATE TB_YD_CRNSCH
					   SET MODIFIER     = :V_MODIFIER
					      ,MOD_DDTT     = SYSDATE
					      ,YD_SCH_PRIOR = TO_NUMBER(:V_YD_SCH_PRIOR)
					      ,YD_EQP_ID    = NVL(:V_YD_EQP_ID,YD_EQP_ID)
					 WHERE YD_WBOOK_ID  = :V_YD_WBOOK_ID
					   AND YD_WRK_PROG_STAT IN ('1','W')
					   AND DEL_YN = 'N'
				 */
				commDao.update(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.updCrnWrkMgtCMCrnSch", logId, methodNm, "크레인스케줄(TB_YD_CRNSCH) 크레인변경 수정");				
				
			}

			slabUtils.printLog(logId, methodNm, "S-");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", "순위변경 완료되었습니다.");
			return jrRtn;
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}	
	}

