    /**
	 * [A] 오퍼레이션명: 위치검색베드(상단부 수정)            
	 * 야드관리 > 후판슬라브야드 [신] > 설비관리 > 위치검색Bed 
	 * PYS 2020-08-24    
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inParam
	 * @return
	 * @throws DAOException
	 */
	public JDTORecord updYdLocSrchRng (GridData gdReq) throws DAOException {
		
		String methodNm = "위치검색베드_수정1[PSlabYdJspSeEJB.updYdLocSrchRng] < " + gdReq.getNavigateValue();
		String logId    = gdReq.getIPAddress();
		String ydEqpId 		= "";

		try{
			slabUtils.printLog(logId, methodNm, "S+");
			String sModifier   = slabUtils.trim(gdReq.getParam("userid" )); 		//수정자(MODIFIER)
			JDTORecord jrRtn   = slabUtils.getParam(logId, methodNm, sModifier);		//Return Value
			JDTORecord jrParam = slabUtils.getParam(logId, methodNm, sModifier);	//DAO Parameter - Log ID, Method, 수정자 Set

			int rowCnt   = gdReq.getHeader("CHECK").getRowCount();

			for (int ii = 0; ii < rowCnt; ii++) {
				
				ydEqpId    = slabUtils.trim(gdReq.getHeader("YD_LOC_SRCH_RNG_REG_SNO").getValue(ii)); 

				if ("".equals(ydEqpId)) {
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", "YD_LOC_SRCH_RNG_REG_SNO가 없습니다.");
					return jrRtn;
				} 

				jrParam.setField("YD_LOC_SRCH_RNG_REG_SNO"      , ydEqpId );

				/**********************************************************
				* 1. 대상 정보 조회 :  위치검색베드_수정대상 정보 조회  
				**********************************************************/
				/* 수정대상 정보 조회 :   
					SELECT YD_SCH_CD                          AS YD_SCH_CD
				      ,YD_ROUTE_GP                            AS YD_ROUTE_GP
				      ,YD_LOC_SRCH_RNG_REG_SNO                AS YD_LOC_SRCH_RNG_REG_SNO
				      ,YD_STR_GTR_CD                          AS YD_STR_GTR_CD
				      ,REGISTER                               AS REGISTER
				      ,TO_CHAR(REG_DDTT, 'YYYYMMDDHH24MISS')  AS REG_DDTT
				      ,MODIFIER                               AS MODIFIER
				      ,TO_CHAR(MOD_DDTT, 'YYYYMMDDHH24MISS')  AS MOD_DDTT
				      ,DEL_YN                                 AS DEL_YN
				      ,YD_LOC_SRCH_RNG_SEQ                    AS YD_LOC_SRCH_RNG_SEQ
				      ,YD_LOC_SRCH_RNG_ACT_STAT               AS YD_LOC_SRCH_RNG_ACT_STAT
				      ,YD_STK_BED_SRCH_METHOD                 AS YD_STK_BED_SRCH_METHOD
				   FROM TB_YD_LOCSRCHRNG
				 WHERE YD_LOC_SRCH_RNG_REG_SNO              = :V_YD_LOC_SRCH_RNG_REG_SNO
				     AND DEL_YN                             = 'N'
				 */
				JDTORecordSet   jsCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.getYdLocsrchrng"  , logId, methodNm, "위치검색베드  수정전조회");
		    		
				if (jsCrnSch == null || jsCrnSch.size() <= 0) {
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", "YD_LOC_SRCH_RNG_REG_SNO [" + ydEqpId + "]의  정보가 존재하지 않습니다.");
					return jrRtn;
			    }
				
				/**********************************************************
				* 2. 대상건 Update : 입력된 내용 update 처리 
				**********************************************************/
				if (jsCrnSch != null && jsCrnSch.size() > 0) {
					JDTORecord jrCrnSch = jsCrnSch.getRecord(0);
					
					// 행선구분 = YD_ROUTE_GP  
					jrParam.setField("YD_ROUTE_GP"     				, slabUtils.nvl(slabUtils.getValue(gdReq, "YD_ROUTE_GP"  	   ,ii), ""    ));
					// 설명      = CD_CONTENTS 
					jrParam.setField("CD_CONTENTS"     				, slabUtils.nvl(slabUtils.getValue(gdReq, "CD_CONTENTS"  	   ,ii), ""    ));
					//저장집합
					jrParam.setField("YD_STR_GTR_CD"             	, slabUtils.nvl(slabUtils.getValue(gdReq, "YD_STR_GTR_CD"  	   ,ii), ""    ));
					jrParam.setField("REGISTER"              		, slabUtils.trim(jrCrnSch.getFieldString("REGISTER"       		))  );
					jrParam.setField("MOD_DDTT"      				, slabUtils.trim(jrCrnSch.getFieldString("MOD_DDTT"       		))  );
					jrParam.setField("DEL_YN"      					, slabUtils.trim(jrCrnSch.getFieldString("DEL_YN"       		))   );
					//범위순서
					jrParam.setField("YD_LOC_SRCH_RNG_SEQ"        	, slabUtils.nvl(slabUtils.getValue(gdReq, "YD_LOC_SRCH_RNG_SEQ"  	   ,ii), ""    ));
					//상태
					jrParam.setField("YD_LOC_SRCH_RNG_ACT_STAT"   	, slabUtils.nvl(slabUtils.getValue(gdReq, "YD_LOC_SRCH_RNG_ACT_STAT"  	   ,ii), ""    ));  
					//검색방법
					jrParam.setField("YD_STK_BED_SRCH_METHOD"     	, slabUtils.nvl(slabUtils.getValue(gdReq, "YD_STK_BED_SRCH_METHOD"  	   ,ii), ""    ));
					jrParam.setField("YD_LOC_SRCH_RNG_REG_SNO"    	, slabUtils.trim(jrCrnSch.getFieldString("YD_LOC_SRCH_RNG_REG_SNO"  ))   );
					jrParam.setField("YD_SCH_CD"    				, slabUtils.nvl(slabUtils.getValue(gdReq, "YD_SCH_CD"  	   ,ii), ""    ));
					
					//검색방법
					jrParam.setField("YD_MPL_EF_YN"    	, slabUtils.nvl(slabUtils.getValue(gdReq, "YD_MPL_EF_YN"  	   ,ii), ""    ));
					jrParam.setField("YD_STK_EF_YN"    	, slabUtils.nvl(slabUtils.getValue(gdReq, "YD_STK_EF_YN"  	   ,ii), ""    ));
					jrParam.setField("YD_BED_GAP_YN"  	, slabUtils.nvl(slabUtils.getValue(gdReq, "YD_BED_GAP_YN"  	   ,ii), ""    ));
				}
				/* 상단부_Update  처리  (TB_YD_LOCSRCHRNG) 
				 * UPDATE TB_YD_LOCSRCHRNG
				   SET MODIFIER                 = :V_MODIFIER
				      ,MOD_DDTT                 = SYSDATE
				      ,DEL_YN                   = :V_DEL_YN
				      ,YD_LOC_SRCH_RNG_ACT_STAT = :V_YD_LOC_SRCH_RNG_ACT_STAT
				      ,YD_STK_BED_SRCH_METHOD   = :V_YD_STK_BED_SRCH_METHOD
				      ,YD_MPL_EF_YN   = :V_YD_MPL_EF_YN
				      ,YD_STK_EF_YN   = :V_YD_STK_EF_YN
				      ,YD_BED_GAP_YN  = :V_YD_BED_GAP_YN
				 WHERE YD_LOC_SRCH_RNG_REG_SNO  = :V_YD_LOC_SRCH_RNG_REG_SNO
				*/
				commDao.update(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.updYdLocsrchrng", logId, methodNm, "대상건 수정");
				/*
				 *  UPDATE TB_YD_SCHRULE                                                
				       SET 
				          MODIFIER             = :V_MODIFIER                                            
				          ,MOD_DDTT             = SYSDATE                                        
				          ,CD_CONTENTS          = :V_CD_CONTENTS                                         
				   WHERE YD_SCH_CD              = :V_YD_SCH_CD   
				 */
				commDao.update(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.updYdSchrule01", logId, methodNm, "스케쥴설명수정");
			}
			slabUtils.printLog(logId, methodNm, "S-");
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", "수정 처리가 완료 되었습니다.");	
			return jrRtn;
			
		} catch(Exception e) {
			throw new DAOException(getClass().getName() + " :: " + e.getMessage(), e);
		}
	}
	
