	/**
	 *  후판슬라브 현재 저장위치 조회(저장위치 체크)
	 * 야드관리 > 후판슬라브야드 [신] > 설비관리 > 저장위치수정 
	 * PYS  2020-08-24
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws JDTOException
	 * @throws JDTOException
	 */
	public JDTORecord chkSlabYdStkPosSlab(GridData gdReq) throws DAOException {
		
		String methodNm  = "현재 저장위치 조회(저장위치 체크) [PSlabYdJspSeEJB.chkSlabYdStkPosSlab] < " + gdReq.getNavigateValue();
		String logId     = gdReq.getIPAddress();	
		String szMsg	 = "";
		
		// 결과 RETRUN용 JDTORecord
		String     sModifier   = ""; 		// 수정자(MODIFIER)
		JDTORecord jrRtn       = null;  	// Return Value
		
		String sSTL_NO				= "";	// to 위치 재료번호 저장용
		JDTORecordSet recordSet 	= null;	// 
		
		try{
			sModifier   = slabUtils.trim(gdReq.getParam("userid" )); 		//수정자(MODIFIER)
			jrRtn       = slabUtils.getParam(logId, methodNm, sModifier);  	//Return Value
			
			slabUtils.printLog(logId, methodNm, "S+");
			
			JDTORecord [] inRecord = slabUtils.genJDTORecordSet(gdReq);
			JDTORecord recTemp     = null;
			
			//전  적치 야드
			for (int nLoop = 0 ; nLoop < inRecord.length ; nLoop++){
				
				recTemp = JDTORecordFactory.getInstance().create();
				recTemp = inRecord[nLoop];
				
				sSTL_NO = slabUtils.paraRecChkNull(recTemp, "STL_NO");
				
				if(sSTL_NO.trim().equals("")){
					continue;
				}
				
				
				// 야드 적치열 조회 > 파라미터 : 적치열, BED번호, 단번호
				slabUtils.printLog(logId,  "*** 적치열 확인  PARAM *** "+ methodNm,"SL");
				slabUtils.printLog(logId, "*** 적치열 확인  PARAM YD_STK_COL_GP(적치열)	: " + recTemp.getFieldString("YD_STK_COL_GP")
				 +"(BED번호): " + recTemp.getFieldString("YD_STK_BED_NO")+"(단번호)	: " + recTemp.getFieldString("YD_STK_LYR_NO") ,"SL");
				
				recordSet = JDTORecordFactory.getInstance().createRecordSet("Yd");
				recordSet = commDao.select(recTemp, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.getPlateShareYdTotCntMgt", logId, methodNm, "적치열 확인");
				
				// 이동하려고 하는 위치에 현재 슬라브가 존재하는지 확인
				if(recordSet.size() > 0 ) {
					szMsg = "To위치에 현재 슬라브가 존재합니다.";
					slabUtils.printLog(logId, szMsg, "SL");
					
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", szMsg);
					
					return jrRtn;
				}
				
			}	 
			
			slabUtils.printLog(logId, methodNm, "S-");
			
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", PSlabYdConstant.RETN_CD_SUCCESS);	// 체크완료 : SUCCESS
			
			return jrRtn;
		
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(getClass().getName() + " :: " + e.getMessage(), e);
		}
	}
	
