    /**
	 * [A] 야드설비(크레인)사양설정 -수정         					 
	 * 야드관리 > 후판슬라브야드 [신] > 설비관리 > 야드설비(크레인)사양설정
	 * PYS 2020-09-02    
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param gdReq
	 * @return
	 * @throws DAOException
	 */
	public JDTORecord updslabYdEqpSetSpec(GridData gdReq) throws DAOException {
		String methodNm = "야드설비(크레인)사양설정 -수정[PSlabYdJspSeEJB.updslabYdEqpSetSpec] < " + gdReq.getNavigateValue();
		String logId 	= gdReq.getIPAddress();
	
		try{
			slabUtils.printLog(logId, methodNm, "S+");
			String sModifier    = slabUtils.trim(gdReq.getParam("userid" )); //수정자(MODIFIER)
			JDTORecord jrRtn   = slabUtils.getParam(logId, methodNm, sModifier);
			JDTORecord jrParam = slabUtils.getParam(logId, methodNm, sModifier);

			String ydEqpId 	   = "";
	
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
	
			for (int ii = 0; ii < rowCnt; ii++) {
				/**********************************************************
				* 0.대상건 select : 조회내역 전체를 건별로 조회 처리
				**********************************************************/
					ydEqpId    = slabUtils.trim(gdReq.getHeader("YD_EQP_ID").getValue(ii));   //설비 ID
					
					if ("".equals(ydEqpId) || (ydEqpId.length() < 6) ) {
						jrRtn.setField("RTN_CD"	, "0");
						jrRtn.setField("RTN_MSG", "설비ID가 올바르지 않습니다.");
						return jrRtn;
					} 
					jrParam.setField("YD_EQP_ID"                  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_EQP_ID", ii),""));

					//설비 ID 및 수정항목 세팅
					jrParam.setField("YD_EQP_NAME"   			  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_EQP_NAME", ii),"") ); 
					jrParam.setField("YD_CRN_GRAB_TP"   		  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_CRN_GRAB_TP", ii),"") ); 
					//YD_EQP_ID
					jrParam.setField("YD_CRN_TONG_H"   			  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_CRN_TONG_H", ii),"") ); 
					jrParam.setField("YD_CRN_TONG_L"   			  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_CRN_TONG_L", ii),"") ); 
					jrParam.setField("YD_CRN_TONG_INTVL_W"   	  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_CRN_TONG_INTVL_W", ii),"") ); 
					jrParam.setField("YD_CRN_TONG_END_T"   		  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_CRN_TONG_END_T", ii),"") ); 
					jrParam.setField("YD_CRN_TONG_W_TOL"   		  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_CRN_TONG_W_TOL", ii),"") ); 
					jrParam.setField("YD_WRK_ABLE_L"   			  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_WRK_ABLE_L", ii),"") ); 
					jrParam.setField("YD_WRK_ABLE_W"   			  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_WRK_ABLE_W", ii),"") ); 
					jrParam.setField("YD_WRK_ABLE_SH"   		  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_WRK_ABLE_SH", ii),"") ); 
					jrParam.setField("YD_WRK_ABLE_WT"   		  , slabUtils.nvl(slabUtils.getValue(gdReq, "YD_WRK_ABLE_WT", ii),"") ); 
					jrParam.setField("DEL_YN"					  , "N");
					
					/*  
					 * 	UPDATE TB_YD_EQP
						SET 
						       MODIFIER 		     = :V_MODIFIER
						      ,MOD_DDTT 		     = SYSDATE
						      ,DEL_YN 		         = :V_DEL_YN
						      ,YD_EQP_NAME 		     = :V_YD_EQP_NAME
						      ,YD_CRN_GRAB_TP 	     = :YD_CRN_GRAB_TP 	
						WHERE YD_EQP_ID              =  :V_YD_EQP_ID
					 * 
					 */
					commDao.insert(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.updYdEqp12", logId, methodNm, "대상건 수정");
					
					/*  
						UPDATE TB_YD_CRNSPEC
						   SET  
						       MODIFIER                 = :V_MODIFIER
						      ,MOD_DDTT                 = SYSDATE
						      ,DEL_YN                   = :V_DEL_YN                
						      ,YD_CRN_GRAB_TP           = :V_YD_CRN_GRAB_TP        
						      ,YD_CRN_TONG_H            = :V_YD_CRN_TONG_H         
						      ,YD_CRN_TONG_L            = :V_YD_CRN_TONG_L         
						      ,YD_CRN_TONG_INTVL_W      = :V_YD_CRN_TONG_INTVL_W   
						      ,YD_CRN_TONG_END_T        = :V_YD_CRN_TONG_END_T     
						      ,YD_CRN_TONG_W_TOL        = :V_YD_CRN_TONG_W_TOL     
						      ,YD_WRK_ABLE_L            = :V_YD_WRK_ABLE_L         
						      ,YD_WRK_ABLE_W            = :V_YD_WRK_ABLE_W         
						      ,YD_WRK_ABLE_SH           = :V_YD_WRK_ABLE_SH        
						      ,YD_WRK_ABLE_WT           = :V_YD_WRK_ABLE_WT        
						 WHERE YD_EQP_ID                = :V_YD_EQP_ID  
					 */
					commDao.insert(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.updYdCrnspec12", logId, methodNm, "대상건 수정");
			}
			
			slabUtils.printLog(logId, methodNm, "S-");
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", "수정처리가 완료 되었습니다.");	
			return jrRtn;
			
		} catch(Exception e) {
			throw new DAOException(getClass().getName() + " :: " + e.getMessage(), e);
		}
	} 

