					jrParam.setField("YD_AIM_RT_GP"     , slabUtils.trim(gdReq.getHeader("YD_AIM_RT_GP").getComboHiddenValues()[gdReq.getHeader("YD_AIM_RT_GP").getSelectedIndex(ii)])         ); //야드목표행선구분
					jrParam.setField("YD_LD_COL_GP"     , slabUtils.trim(gdReq.getHeader("YD_LD_COL_GP").getValue(ii)) );	//야드상차열구분
