        		ydGp  			  = slabUtils.paraRecChkNull(getRecord, "YD_GP");
        		
        		szMsg = "[진도코드갱신 - Y1SetProgCode] " + (szPtTbComm.equals("B") ? "주편" : "슬라브") + "[" + szStlNo + "], ";
        		szMsg += "주문여재구분[" + szOrdYeojaeGp + "],재료구분[" + szStlAppearGp + "], 야드구분[" + ydGp+ "], 슬라브지시행선코드[" 
        		+ szSlabWoRtCd + "], 스카핑여부[" + szScarfingYn + "], 스카핑완료여부[" + szScarfingDoneYn + "], 압연지시여부[" + szMillWoExn + "]";
        		slabUtils.printLog(logId, szMsg, "SL");
        		
