        		szCurrProgCd = slabUtils.paraRecChkNull(getRecord, "CURR_PROG_CD");
        		//전 진도코드
        		szBefoProgCd = slabUtils.paraRecChkNull(getRecord, "BEFO_PROG_CD");
        		//전전진도코드 = 전 진도코드
        		szBefobefoProgCd = szBefoProgCd;
        		//전전진도코드 = 전진도코드
