		//야드 TO위치결정방법
		String ydToLocDcsnMtd = "";
		//야드TO위치가이드
		String ydToLocGuide = "";
		//야드TO위치가이드
		String szSTL_LIST = "";
		//권상모음으로 처리 유무
		boolean bUpCol = true;
