				String sAbmtlGrd		= CmnUtil.getComboList(inDto, "YD_ABMTL_GRD",i);
				String sAbmtlRem		= slabUtils.trim(inDto.getHeader("YD_ABMTL_REM").getValue(i));
				
				slabUtils.printLog(logId, "szSTL_NO : "+sStlNo, "SL");
				slabUtils.printLog(logId, "sAbmtlRsnCd : "+sAbmtlRsnCd, "SL");
				slabUtils.printLog(logId, "sABMTL_HD_MTD_CD : "+sAbmtlHdMtdCd, "SL");
				slabUtils.printLog(logId, "sABMTL_GRD : "+sAbmtlGrd, "SL");
				slabUtils.printLog(logId, "sABMTL_REM : "+sAbmtlRem, "SL");
				slabUtils.printLog(logId, "szYD_USER_ID : "+sModifier+"=="+i, "SL");
				//////////////////////////////////////////////////////////////////
				
				String sPreAbmtlRsnCd  	= "";
