	/**
	 * 후판슬라브야드 차량정지위치 상태 등록 - 수정 
	 * 염용선 2020-10-09
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public JDTORecord updPlateYdCarStopLocStsReg(GridData gdReq) throws DAOException {
		
		String methodNm = "차량정지위치 상태 등록 수정  [PSlabYdJspSeEJB.updPlateYdCarStopLocStsReg] < " + gdReq.getNavigateValue();		
		String logId    = gdReq.getIPAddress();
		
		int intRtnVal = 0;
	
		try {
			slabUtils.printLog(logId, methodNm, "■■■■■■■■■■■■■■+ 차량정지위치 상태 수정 Start.   +■■■■■■■■■■■■■");
			
			String sModifier   = slabUtils.trim(gdReq.getParam("YD_USER_ID" )); 			//수정자(MODIFIER)
			JDTORecord jrParam = slabUtils.getParam(logId, methodNm, sModifier);	
			JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
			JDTORecordSet	carPntInfoSet;													// 차량포인트 조회용
			JDTORecord		carPntInfoRec;													// 차량포인트 조회용
			slabUtils.printLog(logId, methodNm, "S+");
			
			jrParam.setField("YD_STK_COL_GP" 				, slabUtils.trim(gdReq.getParam("YD_STK_COL_GP" )));	// 적치열(차량POINT)
			jrParam.setField("YD_STK_COL_ACT_STAT" 			, slabUtils.trim(gdReq.getParam("COL_ACT_STAT" )));		// 변경할 활성상태
			jrParam.setField("YD_CAR_USE_GP" 				, "");													// 미사용항목
			jrParam.setField("TRN_EQP_CD" 					, "");													// 미사용항목
			jrParam.setField("CAR_NO" 						, "");													// 미사용항목
			jrParam.setField("CARD_NO" 						, "");													// 미사용항목
			jrParam.setField("YD_FRM_YN" 					, "");													// 미사용항목
			
			slabUtils.printLog(logId, methodNm, "■■■■■■■■■■■■■■ 1.해당 차량 포인트 상태 에러체크 Start. ■■■■■■■■■■■■■");
			
			/*차량포인트 활성상태 조회 
			SELECT SC.YD_STK_COL_ACT_STAT                        AS YD_STK_COL_ACT_STAT_SC -- 적치열 작업상태
			     , PT.YD_STK_COL_ACT_STAT                        AS YD_STK_COL_ACT_STAT_PT -- 차량포인트 상태
			     , DECODE(SC.YD_CAR_USE_GP, 'L', SC.TRN_EQP_CD -- 구내운송 시
			                              , 'G', SC.CAR_NO     -- 출하 시
			                                   , SC.TRN_EQP_CD ) AS TRN_EQP_CD             -- 운송장비코드
			     
			  FROM USRYDA.TB_YD_STKCOL   SC -- YD_적치열
			     , USRYDA.TB_YD_CARPOINT PT -- YD_차량포인트
			 WHERE SC.YD_STK_COL_GP = PT.YD_STK_COL_GP
			   AND SC.YD_STK_COL_GP = :V_YD_STK_COL_GP
			*/
			slabUtils.printLog(logId, methodNm, ">> 차량포인트 활성상태 조회");
			carPntInfoSet = commDao.select(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.getYdCarPntActStat", logId, methodNm, "차량포인트 활성상태 조회");
			
			slabUtils.printLog(logId, methodNm, ">> 차량포인트 조회 건수 : " + carPntInfoSet.size());
			if(carPntInfoSet.size() < 1){
				
				slabUtils.printLog(logId, methodNm, ">> 차량포인트 정보가 존재하지 않음");
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", "차량포인트 정보가 존재하지 않습니다.");	
				return jrRtn;
				
			}else{
				carPntInfoRec = carPntInfoSet.getRecord(0);
				
				if(!"".equals(carPntInfoRec.getFieldString("TRN_EQP_CD"))){						// 작업 중 차량정보 화인
					slabUtils.printLog(logId, methodNm, ">> 작업중인 차량정보가 있음.");
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", "작업중인 차량이 존재합니다.");	
					return jrRtn;
				}
				
				// 적치열 작업상태 확인 > [C] 사용가능 / [L] 사용중 / [N] 사용불가 /[R] 예약중
				String sYD_STK_COL_ACT_STAT = carPntInfoRec.getFieldString("YD_STK_COL_ACT_STAT_SC");	// 현재 적치열 활성상태
				
				slabUtils.printLog(logId, methodNm, ">> 포인트 활성상태([C]사용가능 [L]사용중 [N]사용불가 [R]예약중) : " + sYD_STK_COL_ACT_STAT);
				if("L".equals(sYD_STK_COL_ACT_STAT)){		// 사용중(작업중)
					slabUtils.printLog(logId, methodNm, ">> 작업중인 차량정보가 있음.");
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", "포인트에 작업중인 차량이 존재합니다.");	
					return jrRtn;
				}else if("R".equals(sYD_STK_COL_ACT_STAT)){	// 예약중
					slabUtils.printLog(logId, methodNm, ">> 작업중인 차량정보가 있음.");
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", "포인트에 예약중인 차량이 존재합니다.");	
					return jrRtn;
				}
			}
			slabUtils.printLog(logId, methodNm, "■■■■■■■■■■■■■■ 1.해당 차량 포인트 상태 에러체크 End.   ■■■■■■■■■■■■■");
			
			
			slabUtils.printLog(logId, methodNm, "■■■■■■■■■■■■■■ 2.적치열 활성상태 수정 Start       ■■■■■■■■■■■■■");
			
			/* 야드적치열 활성상태 수정
			UPDATE TB_YD_STKCOL
				SET    MOD_DDTT             = SYSDATE  
				     , YD_STK_COL_ACT_STAT  = NVL(:V_YD_STK_COL_ACT_STAT ,YD_STK_COL_ACT_STAT)
				     , YD_CAR_USE_GP        = NVL(:V_YD_CAR_USE_GP       ,YD_CAR_USE_GP      )
				     , TRN_EQP_CD           = NVL(:V_TRN_EQP_CD          ,TRN_EQP_CD         )
				     , CAR_NO               = NVL(:V_CAR_NO              ,CAR_NO             )
				     , CARD_NO              = NVL(:V_CARD_NO             ,CARD_NO            )
				     , MODIFIER             = NVL(:V_MODIFIER            ,MODIFIER           ) 
				WHERE YD_STK_COL_GP         = :V_YD_STK_COL_GP
				  AND DEL_YN = 'N'
			*/
			intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.updYdStkcol01", logId, methodNm, "야드적치열 활성상태 수정");
			
			slabUtils.printLog(logId, methodNm, "> 적치열 활성 수정 건수 : " + intRtnVal);
			
			if (intRtnVal < 0) {
				slabUtils.printLog(logId, methodNm, ">> 적치열 활성상태 수정 오류발생");
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", "차량포인트(적치열) 활성상태 수정 시 오류가 발생했습니다.");	
				return jrRtn;	
			}
			slabUtils.printLog(logId, methodNm, "■■■■■■■■■■■■■■ 2.적치열 활성상태 수정 End.        ■■■■■■■■■■■■■");
			
			
			slabUtils.printLog(logId, methodNm, "■■■■■■■■■■■■■■ 3.차량포인트 활성상태 수정 Start     ■■■■■■■■■■■■■");
			
			String sYD_CARPNT_CD = carPntInfoRec.getFieldString("YD_CARPNT_CD");	// 차량포인트코드
			slabUtils.printLog(logId, methodNm, ">> 차량포인트 값 : " + sYD_CARPNT_CD);
			
			/* 차량포인트 활성상태 수정
			UPDATE TB_YD_CARPOINT
				   SET YD_STK_COL_ACT_STAT = NVL(:V_YD_STK_COL_ACT_STAT ,YD_STK_COL_ACT_STAT ) 
				     , TRN_EQP_CD          = NVL(:V_TRN_EQP_CD          ,TRN_EQP_CD          )
				     , CAR_NO              = NVL(:V_CAR_NO              ,CAR_NO              )
				     , CARD_NO             = NVL(:V_CARD_NO             ,CARD_NO             )
				     , YD_FRM_YN           = NVL(:V_YD_FRM_YN           ,YD_FRM_YN           )
				 WHERE YD_CARPNT_CD        = :V_YD_CARPNT_CD
				   AND DEL_YN = 'N'
			*/
			jrParam.setField("YD_CARPNT_CD", sYD_CARPNT_CD);	// 키값 set
			intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabYdJspSeEJB.uptYdCarpoint", logId, methodNm, "차량포인트 활성상태 수정");
			
			slabUtils.printLog(logId, methodNm, "> 차량포인트 활성 수정 건수 : " + intRtnVal);
			if (intRtnVal < 0) {
				slabUtils.printLog(logId, methodNm, ">> 차량포인트 활성상태 수정 오류발생");
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", "차량포인트 활성상태 수정 시 오류가 발생했습니다.");
				return jrRtn;	
				
			}
			
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", "차량포인트 상태 수정이 정상적으로 완료되었습니다.");
			
			slabUtils.printLog(logId, methodNm, "■■■■■■■■■■■■■■ 3.차량포인트 활성상태 수정 End.      ■■■■■■■■■■■■■");
			slabUtils.printLog(logId, methodNm, "■■■■■■■■■■■■■■+ 차량정지위치 상태 수정 End.     +■■■■■■■■■■■■■");
			slabUtils.printLog(logId, methodNm, "S-");
			return jrRtn;	 
			
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
	}	
	

