	/**
	 * IFTest 전송
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param GridData gdReq
	 * @return JDTORecord
	 * @throws DAOException
	*/
	public JDTORecord sndIfTest(GridData gdReq) throws DAOException {
		String methodNm = gdReq.getNavigateValue()+"[I/F]";
		String logId    = gdReq.getIPAddress();

		try {
			slabUtils.printLog(logId, methodNm, "S+", gdReq);

			//Return Value
			JDTORecord jrRtn = null;

			//DAO Parameter - Log ID, Method, 수정자 Set
			JDTORecord jrParam = slabUtils.getParam(logId, methodNm, slabUtils.trim(gdReq.getParam("userid")));

			//레코드 수
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			
			String msgId = slabUtils.trim(gdReq.getParam("IF_ID")); //IFID
			
			for (int ii = 0; ii < rowCnt; ii++) {
				
				jrParam.setField("ITM_VAL"	,slabUtils.getValue(gdReq, "ITM_VAL", ii)); 
				jrParam.setField("IF_ID"	,msgId); 
				jrParam.setField("ITM_SEQ"	,slabUtils.getValue(gdReq, "ITM_SEQ", ii) ); 
				
				commDao.update(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabJspSeEJB.updIfTestData", logId, methodNm, "IFTest 항목값 수정");
			}

			String szMsg      = "";
			String ifClassNm  = "";
			String ifMthNm    = "";
			String ifSndRcvGp = "";
			String ifMthGp    = "";
			String szDate = slabUtils.getCurDate("yyyy/MM/dd HH:mm:ss");		//slabUtils.getDateTime14()
			
			//ifMthGp  		= msgId.substring(4, 5); //IF방법구분(L:EAI, 기타:JMS)
			ifMthGp    		= gdReq.getParam("MTH_GP");
			//ifSndRcvGp 	= "YM".equals(msgId.substring(0, 2)) ? "S" : "R"; //IF송수신구분(송신, 수신)
			ifSndRcvGp 		= gdReq.getParam("SNDRCV_GP");

			slabUtils.printLog(logId, "*msgId:"+msgId+ " ifSndRcvGp:"+ ifSndRcvGp+ " ifMthGp:"+ ifMthGp, "SL");
			
			//큐에 넣을 데이터를 생성 - Log ID, Method, 수정자 Set
			JDTORecord sndData = slabUtils.getParam(logId, methodNm, slabUtils.trim(gdReq.getParam("userid")));

			sndData.setResultCode(logId);	//Log ID
			sndData.setResultMsg(methodNm);	//Log Method Name			
			sndData.setField("JMS_TC_CD"         , msgId                    );
			sndData.setField("JMS_TC_CREATE_DDTT", szDate);  
			
			if ("E".equals(ifMthGp) && "S".equals(ifSndRcvGp)) {
				//EAI송신처리 일 경우
				ifClassNm = "PSlabYdCommEJB";
				ifMthNm   = "sndToEAI";
				slabUtils.printLog(logId, ""+ ifMthGp, "SL");

				//EAI전문 Message
				StringBuffer sbMsg = new StringBuffer();

				for (int ii = 0; ii < rowCnt; ii++) {

					sbMsg = sbMsg.append(gdReq.getHeader("ITM_VAL").getValue(ii));
					slabUtils.printLog(logId, ii+"=="+ sbMsg, "SL");
				}
				sndData.setField("JMS_TC_MESSAGE", sbMsg.toString());
				
			} else {
				if("Y".equals(gdReq.getParam("EFF_YN_TEST"))) {  //신규모듈 적용여부 테스트 

					//신규모듈 적용여부 테스트 CheckBox 체크시 TB_YM_Z_IF 테이블의 BEF_PGM_NM1, BEF_PGM_NM2 을 읽어 호출 한다.
					ifClassNm = gdReq.getParam("BEF_PGM_NM1");
					ifMthNm   = gdReq.getParam("BEF_PGM_NM2");	//EJB Call
					
					szMsg="[ (BEF)"+methodNm+"] ifClassNm:" + ifClassNm + " , ifMthNm:" + ifMthNm ;
					slabUtils.printLog(logId, szMsg, "SL");			    		
					
				} else {
					//수신 처리방법(Q:JMS Queue, E:EJB Call)이 'E'이고 수신처가 야드이면
					if ("E".equals(gdReq.getParam("TRT_MTH")) ) {
						ifClassNm = "PSlabYdCommEJB";
						ifMthNm = "rcvInterface";	//EJB Call
						
					} else {
						ifClassNm = "PSlabYdCommEJB";
						ifMthNm = "sndToJMS";		//JMS송신
					}
				}
				
				//EAI송신 외 처리 일 경우
				for (int ii = 0; ii < rowCnt; ii++) {
					if(!"".equals(slabUtils.trim(gdReq.getHeader("ITM_VAL").getValue(ii)))) {
					//	slabUtils.printLog(logId, slabUtils.trim(gdReq.getHeader("ITM_ID" ).getValue(ii))
					//	  +"(" +ii +")"+" --->" + slabUtils.trim(gdReq.getHeader("ITM_VAL").getValue(ii)) , "SL");
					}
					sndData.setField(slabUtils.trim(gdReq.getHeader("ITM_ID" ).getValue(ii))
							       , slabUtils.trim(gdReq.getHeader("ITM_VAL").getValue(ii)));
				}
			}
			
			//++++++++++++++++++++  ydEjbCon.trx("PSlabYdCommEJB", "rcvInterface", inRecord);
			//송신 공통 EJB를 이용하여 전송
			EJBConnector ejbConn = new EJBConnector("default", ifClassNm, this);
			ejbConn.trx(ifMthNm, new Class[] { JDTORecord.class }, new Object[] { sndData });
			
			slabUtils.printLog(logId, methodNm, "S-");

			return jrRtn;
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}	
	} // end of sndIfTest
	
	/**
	 * IFTest EAI전송
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param GridData gdReq
	 * @return JDTORecord
	 * @throws DAOException
	*/
	public GridData sndIfTestEAI(GridData gdReq) throws DAOException {
		String methodNm = gdReq.getNavigateValue();
		String logId    = gdReq.getIPAddress();

		try {
			slabUtils.printLog(logId, methodNm, "S+", gdReq);
			String tcList = gdReq.getParam("TC_LIST"); //전송List
			String tcMsg  = ""; //전송Data
			int sndCnt = 0; //전송건수
			
			slabUtils.printLog(logId, "(in)"+tcList, "SL");

			while (tcList.length() > 0) {
				int idx = tcList.indexOf("\r\n");
				
				if (idx > 0) {
					tcMsg  = tcList.substring(0, idx);
					tcList = tcList.substring(idx + 2);
				} else {
					tcMsg = tcList;
					tcList = "";
				}

				//한건 전송
				if (!"".equals(tcMsg) && tcMsg.length() > 60) {
					//큐에 넣을 데이터를 생성 - Log ID, Method, 수정자 Set
					JDTORecord sndData = slabUtils.getParam(logId, methodNm, slabUtils.trim(gdReq.getParam("userid")));

					sndData.setResultCode(logId);	//Log ID
					sndData.setResultMsg(methodNm);	//Log Method Name
					//EAI송신처리 일 경우
					sndData.setField("JMS_TC_CD"         , tcMsg.substring(0, 8));
					sndData.setField("JMS_TC_CREATE_DDTT", slabUtils.getDateTime14());
					sndData.setField("JMS_TC_MESSAGE"    , tcMsg);

					//송신 공통 EJB를 이용하여 L2로 전송
					EJBConnector ejbConn = new EJBConnector("default", "PSlabYdCommEJB", this);
					ejbConn.trx("sndToEAI", new Class[] { JDTORecord.class }, new Object[] { sndData });

					sndCnt++;
				}
			}

			gdReq.addParam("SND_CNT", String.valueOf(sndCnt));
			
			slabUtils.printLog(logId, methodNm, "S-");

			return gdReq;
			
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}	
	}  

