	/**
	 * 화면 도움말 - 등록
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param GridData gdReq
	 * @return JDTORecord
	 * @throws DAOException
	*/
	public JDTORecord setPageHelpInfo(GridData gdReq) throws DAOException {
		String methodNm = "화면 도움말 등록[PSlabYdJspSeEJB.setPageHelpInfo] < " + gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();

		try {
			slabUtils.printLog(logId, methodNm, "S+", gdReq);
			
			//Return Value
			JDTORecord jrRtn = slabUtils.getParam(logId, methodNm, slabUtils.trim(gdReq.getParam("userid")));;;

			//DAO Parameter - Log ID, Method, 수정자 Set
			JDTORecord jrParam = slabUtils.getParam(logId, methodNm, slabUtils.trim(gdReq.getParam("userid")));
			/*
			 MERGE INTO USRYDA.TB_YD_HELP A  -- YM_도움말
			 USING (SELECT    :V_PAGE_ID     AS PAGE_ID      -- 화면ID   
			                , :V_PAGE_PT     AS PAGE_PT      -- 화면개요 
			                , :V_SCR_REMARK  AS SCR_REMARK   -- 특기사항 
			                , :V_DEL_YN      AS DEL_YN       -- 삭제여부 
			                , :V_REGISTER    AS REGISTER     -- 등록자   
			                , :V_MODIFIER    AS MODIFIER     -- 수정자   
			          FROM DUAL
			       ) B
			    ON (    A.PAGE_ID = TO_NUMBER(B.PAGE_ID)   )
			WHEN NOT MATCHED THEN 
			     INSERT      
			            (                                                                          
			              A.PAGE_ID      -- 화면ID   
			            , A.PAGE_PT      -- 화면개요 
			            , A.SCR_REMARK   -- 특기사항 
			            , A.DEL_YN       -- 삭제여부 
			            , A.REGISTER     -- 등록자   
			            , A.REG_DDTT     -- 등록 일시
			            , A.MODIFIER     -- 수정자   
			            , A.MOD_DDTT     -- 수정 일시
			            )                                                                          
			     VALUES (
			              B.PAGE_ID      -- 화면ID   
			            , B.PAGE_PT      -- 화면개요 
			            , B.SCR_REMARK   -- 특기사항 
			            , 'N'            -- 삭제여부 
			            , B.REGISTER     -- 등록자   
			            , SYSDATE        -- 등록 일시
			            , B.MODIFIER     -- 수정자   
			            , SYSDATE        -- 수정 일시
			            )                                                                          
			WHEN MATCHED THEN 
			 UPDATE      
			    SET   A.PAGE_PT      = B.PAGE_PT    -- 화면개요 
			        , A.SCR_REMARK   = B.SCR_REMARK -- 특기사항 
			        , A.DEL_YN       = B.DEL_YN     -- 삭제여부 
			        , A.MODIFIER     = B.MODIFIER   -- 수정자   
			        , A.MOD_DDTT     = SYSDATE      -- 수정 일시
			  WHERE A.PAGE_ID        = TO_NUMBER(B.PAGE_ID)
			 */
			jrParam.setField("PAGE_ID"		,gdReq.getParam("PAGE_ID"	)); 
			jrParam.setField("PAGE_PT"		,gdReq.getParam("PAGE_PT"	)); 
			jrParam.setField("SCR_REMARK"	,gdReq.getParam("SCR_REMARK")); 
			jrParam.setField("DEL_YN"		,gdReq.getParam("DEL_YN"	)); 
			jrParam.setField("REGISTER"		,gdReq.getParam("REGISTER"	)); 
			String queryId = "com.inisteel.cim.yd.pslabyd.dao.PSlabYdMvCarSeEJB.setPageHelpInfo"; 
			commDao.update(jrParam, queryId, logId, methodNm, "화면도움말등록");
			slabUtils.printLog(logId, methodNm, "S-");
			
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", "화면 도움말 - 등록처리 완료");
			return jrRtn;
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}	
	} // end of updPageHelpInfo
	
	
	/**
	 * 화면 도움말 - 버튼등록
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param GridData gdReq
	 * @return JDTORecord
	 * @throws DAOException
	*/
	public JDTORecord setPageHelpBtnInfo(GridData gdReq) throws DAOException {
		String methodNm = "화면 도움말 - 버튼등록[PSlabYdJspSeEJB.setPageHelpBtnInfo] < " + gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();

		try {
			slabUtils.printLog(logId, methodNm, "S+", gdReq);

			//Return Value
			JDTORecord jrRtn = slabUtils.getParam(logId, methodNm, slabUtils.trim(gdReq.getParam("userid")));;

			//DAO Parameter - Log ID, Method, 수정자 Set
			JDTORecord jrParam = slabUtils.getParam(logId, methodNm, slabUtils.trim(gdReq.getParam("userid")));

			//수정할 레코드 수
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
		
			/* 화면 도움말 - 이전 버전 버튼 미사용 처리(신규버전 버튼정보 입력 전 실행) 
			UPDATE USRYDA.TB_YD_HELP_BTN B
			   SET  B.DEL_YN  = 'Y'    -- 삭제여부   
			WHERE   B.PAGE_ID = :V_PAGE_ID   -- 화면ID
			*/
			jrParam.setField("PAGE_ID", gdReq.getParam("PAGE_ID"));
			String queryId = "com.inisteel.cim.yd.pslabyd.dao.PSlabYdMvCarSeEJB.updPageHelpBtnRvsInit";
			commDao.update(jrParam, queryId, logId, methodNm, "이전 버전 버튼 미사용 처리");
			
			/* 화면 도움말 - 버튼 다음 버전 조회  
			SELECT NVL(MAX(RVS_NO), 0) +1 AS RVS_NO
			  FROM USRYDA.TB_YD_HELP_BTN B
			 WHERE B.PAGE_ID = :V_PAGE_ID   -- 화면ID
			*/
			queryId = "com.inisteel.cim.yd.pslabyd.dao.PSlabYdMvCarSeEJB.getPageHelpBtnNextRvsNo";
			String nextRvsNo = commDao.select(jrParam, queryId, logId, methodNm, "다음 버전 조회").getRecord(0).getFieldString("RVS_NO");
			
			for (int ii = 0; ii < rowCnt; ii++) {
				
				// 파라미터 Set.
				jrParam.setField("PAGE_ID"	,slabUtils.getValue(gdReq, "PAGE_ID"	, ii)	); 
				jrParam.setField("BTN_ID"	,slabUtils.getValue(gdReq, "BTN_ID"		, ii)	);
				jrParam.setField("BTN_NM"	,slabUtils.getValue(gdReq, "BTN_NM"		, ii)	);
				jrParam.setField("RVS_NO"	,nextRvsNo 										);
				jrParam.setField("BTN_IMG_PATH"	,slabUtils.getValue(gdReq, "BTN_IMG_PATH"		, ii)	);
				jrParam.setField("BTN_DISC"	,slabUtils.getValue(gdReq, "BTN_DISC"	, ii)	);
				jrParam.setField("REGISTER"	,slabUtils.getValue(gdReq, "REGISTER"	, ii)	);
				jrParam.setField("MODIFIER"	,slabUtils.getValue(gdReq, "MODIFIER"	, ii)	);
				
				/* 후판슬라브야드 YD 화면 도움말 - 버튼등록 -- com.inisteel.cim.yd.pslabyd.dao.PSlabYdMvCarSeEJB.setPageHelpBtnInfo
 
					INSERT INTO USRYDA.TB_YD_HELP_BTN B(
					      B.PAGE_ID   -- 화면ID     
					    , B.BTN_ID    -- 버튼ID
					    , B.BTN_NM    -- 버튼명
					    , B.RVS_NO    -- Revision
					    , B.BTN_IMG_PATH -- 버튼 이미지 경로
					    , B.BTN_DISC  -- Discription
					    , B.BTN_SEQ   -- 순번       
					    , B.DEL_YN    -- 삭제여부   
					    , B.REGISTER  -- 등록자     
					    , B.REG_DDTT  -- 등록 일시  
					    , B.MODIFIER  -- 수정자     
					    , B.MOD_DDTT  -- 수정 일시  
					) VALUES (
					      :V_PAGE_ID   -- 화면ID     
					    , :V_BTN_ID    -- 버튼ID
					    , :V_BTN_NM    -- 버튼명
					    , :V_RVS_NO    -- 버전       
					    , :V_BTN_IMG_PATH -- 버튼 이미지 경로
					    , :V_BTN_DISC  -- Discription
					    , (SELECT NVL(MAX(BTN_SEQ)+1, 1) FROM USRYMA.TB_YM_HELP_BTN WHERE PAGE_ID = :V_PAGE_ID)   -- 순번       
					    , 'N'          -- 삭제여부   
					    , :V_REGISTER  -- 등록자     
					    , SYSDATE      -- 등록 일시  
					    , :V_MODIFIER  -- 수정자     
					    , SYSDATE      -- 수정 일시  
					)
				 */
				commDao.update(jrParam, "com.inisteel.cim.yd.pslabyd.dao.PSlabYdMvCarSeEJB.setPageHelpBtnInfo", logId, methodNm, "후판슬라브 YD 화면 도움말 - 버튼등록");
			}

			slabUtils.printLog(logId, methodNm, "S-");
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", "화면 도움말 - 버튼등록 - 정상 처리");
			return jrRtn;
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}	
	} // end of setPageHelpBtnInfo
	
	
