    /**
     * 구입슬라브 입고등록 - 현재 진도코드, 입고일자, 입고시간 조회
     * 
     * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
     * @param GridData gdReq
     * @return GridData
     * @throws Exception
     */
    public GridData getListSendStackInfo(GridData gdReq) throws Exception {
        String methodNm = "구입슬라브 입고등록 - 현재 진도코드, 입고일자, 입고시간 조회[PSlabYdJspSeEJB.getListSendStackInfo] < " + gdReq.getNavigateValue();
        String logId    = slabUtils.getLogId();
        
        slabUtils.printLog(logId, methodNm, "S+");
        
        String s_SlabNoHd = StringHelper.evl(gdReq.getParam("SLAB_NO_HD"),   "");  //SLAB 번호
        
        //Grid date 를 JDTORecord data 로 변환 & DB Call
        JDTORecord jrInParam = CmUtil.genJDTORecord(gdReq);
                   jrInParam.setField("SLAB_NO_HD",   s_SlabNoHd);
        
        try {
            
            String queryId = "yd.slabtot.slabStackReg.getListSendStackInfo";
            JDTORecordSet jsOutSet  = commDao.select(jrInParam, queryId, logId, methodNm, "");

            //UI로 반환 할 Grid data 를 생성 
            GridData gdRtn = OperateGridData.cloneResponseGridData(gdReq);
            GridData gdRet = slabUtils.jdtoRecordToGridData(gdRtn, jsOutSet.toList(), gdReq);
            
            slabUtils.printLog(logId, methodNm, "S-");
            
            if(jsOutSet.size() < 1) {
                gdRet.setMessage("2"+MessageHelper.getUserMessage("MSG0034", new String[] {"Slab정보"}, "Slab정보이/가 존재하지 않습니다."));
            } else {
                gdRet.setMessage("0");
            }
            return gdRet;
            
        } catch(DAOException e) {
            throw e;
        } catch(Exception e) {
            throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
        }
    }   

