    /**
     * 수출슬라브 출고처리 - 출고등록
     *
     * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
     * @param GridData gdReq
     * @return JDTORecord
     * @throws DAOException
    */
    public JDTORecord setMSSlabIssueReg(GridData gdReq) throws DAOException {
        String methodNm = "수출슬라브 출고처리 - 출고등록[PSlabYdJspSeEJB.setMSSlabIssueReg] < " + gdReq.getNavigateValue();
        String logId = gdReq.getIPAddress();

        try {
            slabUtils.printLog(logId, methodNm, "S+", gdReq);
            
            //Return Value
            JDTORecord jrRtn = slabUtils.getParam(logId, methodNm, slabUtils.trim(gdReq.getParam("userid")));
            
            //Grid date 를 JDTORecord data 로 변환
            JDTORecord jrInParam  = CmUtil.genJDTORecord(gdReq);        //파라미터 (GridData > 변수들)            -> JDTORecord
            
            
            String s_SLAB_NO_HD   = StringHelper.evl(gdReq.getParam("SLAB_NO_HD"),   "");
            String s_YD           = StringHelper.evl(gdReq.getParam("YD"),           "");
            String s_BAY          = StringHelper.evl(gdReq.getParam("BAY"),          "");
            String s_SPAN         = StringHelper.evl(gdReq.getParam("SPAN"),         "");
            String s_COL          = StringHelper.evl(gdReq.getParam("COL"),          "");
            String s_CELLNO       = StringHelper.evl(gdReq.getParam("CELLNO"),       "");
            String s_LAYER        = StringHelper.evl(gdReq.getParam("LAYER"),        "");
            String s_YD_EQP_ID    = StringHelper.evl(gdReq.getParam("YD_EQP_ID"),    "");
            
            s_SPAN   = this.transLoc(s_SPAN);
            s_COL    = this.transLoc(s_COL);
            s_CELLNO = this.transLoc(s_CELLNO);
            s_LAYER  = this.transLoc(s_LAYER);
            
            String s_FROM_STORE_LOC_CD = s_YD + s_BAY + s_SPAN + s_COL + s_CELLNO + s_LAYER;
            
            //기준일자 구하기 시작
            String s_RULE_DATE = null;
            String s_ORD_DATE  = slabUtils.getCurDate("yyyyMMdd");
            String s_ORD_TIME  = slabUtils.getCurDate("HHmmss");
            
            CodeUtil bean = new CodeUtil();        
            String[][] as_RULE_DATE  = bean.getListClass2Code("PS046", "04");      //주야시작시간
            String s_DATE_START_TIME = slabUtils.getCodeStringF(as_RULE_DATE,"D");
            
            int OrdTime       = Integer.parseInt(s_ORD_TIME);
            int DateStartTime = Integer.parseInt(s_DATE_START_TIME);
            
            if(OrdTime < DateStartTime) {
                
               String s_year  = s_ORD_DATE.substring(0,4);
               String s_month = s_ORD_DATE.substring(4,6);
               String s_day   = s_ORD_DATE.substring(6,8);
               
               int year  = Integer.parseInt(s_year);
               int month = Integer.parseInt(s_month);
               int day   = Integer.parseInt(s_day); 
               
               if("01".equals(s_month)) {
                   
                   if("01".equals(s_day)) {
                       year = year -1;
                       s_year = String.valueOf(year);
                       s_RULE_DATE = s_year + "1231";
                   } else {
                       day = day - 1;
                       if(day < 10) {
                           s_day = "0" + String.valueOf(day);
                       } else {
                           s_day = String.valueOf(day);
                       }
                       s_RULE_DATE = s_year + s_month + s_day;
                   }
                   
               } else {
                   
                   if("01".equals(s_day)) {
                       month = month - 1;
                       if(month < 10) {
                           s_month = "0" + String.valueOf(month);
                       } else {
                           s_month = String.valueOf(month);
                       }
                       s_RULE_DATE = s_year + s_month + slabUtils.getLastday(s_year, s_month);
                   } else {
                       day = day - 1;
                       if(day < 10) {
                           s_day = "0" + String.valueOf(day);
                       } else {
                           s_day = String.valueOf(day);
                       }
                       s_RULE_DATE = s_year + s_month + s_day;
                   }
               }
               
            } else {
               s_RULE_DATE = s_ORD_DATE;   
            }
            
            
            //jrInParam에 있는 변수값 변경 또는 변수 추가
            jrInParam.setField("SLAB_NO_HD",        StringHelper.evl(s_SLAB_NO_HD.trim(), "")); 
            jrInParam.setField("YD",                StringHelper.evl(s_YD.trim(), ""));
            jrInParam.setField("BAY",               StringHelper.evl(s_BAY.trim(), ""));
            jrInParam.setField("FROM_STORE_LOC_CD", StringHelper.evl(s_FROM_STORE_LOC_CD.trim(), ""));
            jrInParam.setField("RULE_DATE",         StringHelper.evl(s_RULE_DATE.trim(), ""));
            jrInParam.setField("YD_EQP_ID",         StringHelper.evl(s_YD_EQP_ID.trim(), ""));
            
            String queryId = "";
            
            try {
                
                int iRtnVal = 0;
                
                //UPDATE
                queryId = "yd.slabtot.slabIssueReg.updateYardMapInfo";
                iRtnVal = commDao.update(jrInParam, queryId, logId, methodNm, "");

                if(iRtnVal == 0) {
                    jrRtn.setField("RTN_CD" , "0");
                    jrRtn.setField("RTN_MSG", "MSG0034");
                    return jrRtn;
                }
                
                //INSERT
                queryId = "yd.slabtot.slabIssueReg.insertWorkHistory";
                iRtnVal = commDao.update(jrInParam, queryId, logId, methodNm, "");
                
                if(iRtnVal == 0) {
                    jrRtn.setField("RTN_CD" , "0");
                    jrRtn.setField("RTN_MSG", "MSG0034");
                    return jrRtn;
                }
                
                if(iRtnVal == 1) {
                    jrRtn.setField("RTN_CD" , "1");
                    jrRtn.setField("RTN_MSG", "0"+MessageHelper.getUserMessage("MSG0042", new String[] {"출고등록"}, "출고등록이 정상적으로 완료되었습니다."));
                    return jrRtn;
                }
                
            }catch (Exception e){
                throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
            }
            
            slabUtils.printLog(logId, methodNm, "S-");
            
            return jrRtn;
            
        } catch(DAOException e) {
            throw e;
        } catch(Exception e) {
            throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
        }   
    } // end of setPageHelpBtnInfo

    /**
     * 
     * @param location
     * @return
     */
    public static String transLoc(String location) {
        
        String locationToStr = "";
        
        int locationTo = Integer.parseInt(location);
        if(locationTo<10){
            locationToStr = "0"+location;       
        } else {
            locationToStr = location;
        }
        
        return locationToStr;
    }

